fn activity_selection(start: List[Int], end_: List[Int]) -> Int:
    var n = len(start)
    var acts = List[Tuple[Int, Int]]()
    for i in range(n):
        acts.append((end_[i], start[i]))
    sort(acts)
    var count = 0
    var last_end = -1
    for act in acts:
        var s = act[].get[1, Int]()
        var e = act[].get[0, Int]()
        if s >= last_end:
            count += 1
            last_end = e
    return count
